// Markdown content negotiation for blog posts.
//
// When a request to `/blog/<slug>/` (or `/blog/<slug>`) carries
// `Accept: text/markdown` (with no preference for HTML), rewrite the
// request to the build-time markdown variant at `/blog/<slug>.md`
// generated by `src/pages/blog/[slug].md.ts`.  Browsers requesting
// HTML are unaffected.
//
// The site advertises `Vary: Accept` on every response from this path
// so caches don't conflate the two representations.
//
// Per Cloudflare's "Markdown for Agents" check on isitagentready.com,
// the response should also carry `Content-Type: text/markdown` — the
// underlying .md endpoint already does that.

export default async (request, context) => {
  const url = new URL(request.url);

  // Skip the .md artifacts themselves so we never loop back through.
  if (url.pathname.endsWith('.md')) return context.next();

  // Map canonical HTML URLs to their .md variants.  Two cases today:
  //   `/`             -> `/index.md`
  //   `/blog/<slug>`  -> `/blog/<slug>.md`
  // Add new branches here as more pages get markdown variants.
  const mdPath = mapToMarkdown(url.pathname);
  if (!mdPath) return context.next();

  // Decide whether the client prefers markdown.  Accept either an explicit
  // `text/markdown` listing or `text/markdown` with q-value at least as
  // high as `text/html`.  Bare `*/*` falls through to HTML.
  const accept = request.headers.get('accept') ?? '';
  if (!prefersMarkdown(accept)) {
    // Still surface Vary so caches store the HTML variant correctly.
    const response = await context.next();
    response.headers.set('Vary', 'Accept');
    return response;
  }

  // Rewrite to the build-time `.md` artifact.  fetch() rather than redirect
  // so the agent gets the markdown in one round-trip and the canonical URL
  // stays in the address bar.
  const rewritten = new URL(url);
  rewritten.pathname = mdPath;
  const response = await fetch(rewritten, request);

  // Re-emit as a fresh response so we can normalize headers.
  const body = await response.arrayBuffer();
  return new Response(body, {
    status: response.status,
    headers: {
      'Content-Type': 'text/markdown; charset=utf-8',
      'Vary': 'Accept',
      'Cache-Control': response.headers.get('cache-control') ?? 'public, max-age=300',
    },
  });
};

function mapToMarkdown(pathname) {
  if (pathname === '/' || pathname === '') return '/index.md';
  const m = pathname.match(/^\/blog\/([^/]+)\/?$/);
  if (m) return `/blog/${m[1]}.md`;
  return null;
}

function prefersMarkdown(accept) {
  if (!accept) return false;
  const types = accept
    .split(',')
    .map(s => s.trim().toLowerCase())
    .map(s => {
      const [type, ...params] = s.split(';').map(p => p.trim());
      const qParam = params.find(p => p.startsWith('q='));
      const q = qParam ? parseFloat(qParam.slice(2)) : 1.0;
      return { type, q: Number.isFinite(q) ? q : 1.0 };
    });
  const md = types.find(t => t.type === 'text/markdown');
  if (!md) return false;
  const html = types.find(t => t.type === 'text/html');
  // No HTML mentioned, or markdown ranked at least as high → markdown wins.
  return !html || md.q >= html.q;
}
